// Utilitário para persistir o histórico de arquivos de postes no localStorage

const STORAGE_KEY = 'historicoArquivosCompartilhamentoPostes';

export function salvarHistoricoPostesNoStorage(historico) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(historico));
  } catch (e) {}
}

export function carregarHistoricoPostesDoStorage() {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    return [];
  }
}
