import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const cores = {
  NOVO: '#1976d2',      // Azul
  ATIVO: '#388e3c',    // Verde
  CORRIGIR: '#fbc02d', // Amarelo
  SUSPENSO: '#d32f2f'  // Vermelho
};

const nomes = {
  NOVO: 'Novos',
  ATIVO: 'Ativos',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspensos'
};

function agruparPorStatus(clientes) {
  return clientes.reduce((acc, cliente) => {
    acc[cliente.status] = acc[cliente.status] || [];
    acc[cliente.status].push(cliente);
    return acc;
  }, {});
}

const ListaClientes = ({ atualizar, consultoriaFiltro }) => {
  const [clientes, setClientes] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchClientes = async () => {
    setLoading(true);
    const resp = await fetch('http://localhost:5000/api/clientes');
    const data = await resp.json();
    setClientes(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchClientes();
    // eslint-disable-next-line
  }, [atualizar]);

  const handleStatus = async (id, status) => {
    await fetch(`http://localhost:5000/api/clientes/${id}/status`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status })
    });
    fetchClientes();
  };

  const handleExcluir = async (id) => {
    if(window.confirm('Tem certeza que deseja excluir este cliente?')) {
      await fetch(`http://localhost:5000/api/clientes/${id}`, {
        method: 'DELETE'
      });
      fetchClientes();
    }
  };

  if (loading) return <p>Carregando clientes...</p>;
  // Filtrar por consultoria se filtro estiver ativo
  const clientesFiltrados = consultoriaFiltro
    ? clientes.filter(c => c.consultoria === consultoriaFiltro)
    : clientes;
  const agrupados = agruparPorStatus(clientesFiltrados);

  return (
    <div>
      {['NOVO','ATIVO','CORRIGIR','SUSPENSO'].map(status => (
        <div key={status} style={{marginBottom:'2rem'}}>
          <h3 style={{color:cores[status]}}>{nomes[status]}</h3>
          {(agrupados[status]||[]).length === 0 && <p style={{color:'#888'}}>Nenhum cliente.</p>}
          {(agrupados[status]||[]).map(cliente => (
            <div key={cliente.id} style={{background:cores[status],color:'#fff',padding:'1rem',borderRadius:'6px',marginBottom:'0.5rem',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div>
                <strong>{cliente.cnpj} - {cliente.razaoSocial}</strong><br/>
                <span>Consultoria: {cliente.consultoria}</span>
              </div>
              <div style={{display:'flex',alignItems:'center',gap:'0.5rem'}}>
                <select value={cliente.status} onChange={e=>handleStatus(cliente.id, e.target.value)} style={{marginRight:'1rem'}}>
                  <option value="NOVO">Novo</option>
                  <option value="ATIVO">Ativo</option>
                  <option value="CORRIGIR">Corrigir</option>
                  <option value="SUSPENSO">Suspenso</option>
                </select>
                <Link to={`/cliente/${cliente.id}`} style={{background:'#fff',color:cores[status],padding:'0.3rem 1rem',borderRadius:'4px',textDecoration:'none',fontWeight:'bold'}}>Detalhes</Link>
                <button onClick={()=>handleExcluir(cliente.id)} style={{background:'#222',color:'#fff',border:'none',borderRadius:'4px',padding:'0.3rem 1rem',fontWeight:'bold',cursor:'pointer'}}>Excluir</button>
              </div>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

export default ListaClientes;
